INSERT INTO `itineraries` VALUES (299,5,1,'Arrival in Arusha','Arrive at Kilimanjaro International Airport. Private transfer to your Arusha lodge with welcome dinner and detailed safari briefing.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',4,NULL,NULL,NULL,NULL),(300,5,2,'Lake Manyara National Park','Drive to the breathtaking Lake Manyara, shimmering at the base of the Rift Valley escarpment. Search for tree-climbing lions, hippo pods, flamingo flocks and over 400 bird species in this compact gem.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',6,17,NULL,NULL,NULL),(301,5,3,'Tarangire National Park','A full day in Tarangire — famous for its ancient baobabs and massive elephant herds. Game drives along the river reveal lion, leopard, python and herds of wildebeest and zebra.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',5,7,NULL,NULL,NULL),(302,5,4,'Karatu to Serengeti — Olduvai Gorge','Cross the Ngorongoro Highlands, stopping at Olduvai Gorge — the \"Cradle of Mankind\". Descend into the Serengeti for afternoon game drives across the endless plains.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',1,3,NULL,NULL,NULL),(303,5,5,'Full Day in the Serengeti','Explore the Serengeti from dawn to dusk. Morning and afternoon game drives revealing lion prides, leopard in sausage trees, cheetah hunts, and vast herds of herbivores. Optional balloon safari at sunrise.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',1,3,NULL,NULL,NULL),(304,5,6,'Serengeti — Northern Sector','Drive north toward the Mara River region. This area is famous for dramatic wildebeest river crossings. Big cats and crocodile sightings are frequent. Picnic lunch on the savanna.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',1,3,NULL,NULL,NULL),(305,5,7,'Ngorongoro Crater Descent','Early departure for the Ngorongoro Crater. Descend 600 metres into the caldera for a half-day game drive — spot black rhino, lion, elephant, buffalo and hippo in this extraordinary natural arena.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',2,16,NULL,NULL,NULL),(306,5,8,'Ngorongoro to Arusha — Departure','Morning drive through the green Karatu highlands back to Arusha. Farewell lunch, souvenir shopping, and transfer to Kilimanjaro Airport.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',4,NULL,NULL,NULL,NULL),(307,6,1,'Arrival in Arusha','Welcome to Tanzania! Private VIP transfer to a boutique lodge in Arusha. Enjoy a romantic welcome dinner with views of Mount Meru.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',4,NULL,NULL,NULL,NULL),(308,6,2,'Tarangire & Sundowner','Morning game drive in Tarangire among elephant herds and baobab groves. Late afternoon sundowner cocktails on a private lookout over the Rift Valley.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',5,7,NULL,NULL,NULL),(309,6,3,'Serengeti — Private Bush Camp','Fly by charter to the Serengeti. Settle into your luxury tented camp with private plunge pool. Afternoon game drive followed by a bush dinner under a canopy of stars.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',1,6,NULL,NULL,NULL),(310,6,4,'Serengeti — Balloon & Bush Breakfast','Rise before dawn for a hot-air balloon flight over the Serengeti. Land for a champagne bush breakfast on the savanna. Afternoon game drive focused on big cat territory.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',1,6,NULL,NULL,NULL),(311,6,5,'Ngorongoro Crater','Fly or drive to Ngorongoro. Descend into the crater for a romantic picnic lunch surrounded by the Big Five. Overnight at the iconic crater rim lodge.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',2,5,NULL,NULL,NULL),(312,6,6,'Fly to Zanzibar — Beach & Spice','Morning flight to Zanzibar. Transfer to your beachfront resort. Afternoon at leisure — relax on white-sand beaches or explore Stone Town. Sunset dhow cruise.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',20,NULL,NULL,NULL,NULL),(313,6,7,'Zanzibar & Departure','Morning spa treatment and beach time. Optional spice tour or snorkelling before afternoon transfer to Zanzibar Airport for your onward journey.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',20,NULL,NULL,NULL,NULL),(314,7,1,'Arrival in Arusha','Family welcome at Kilimanjaro Airport. Transfer to your family-friendly lodge in Arusha with kids\' activity pack and safari briefing.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',4,NULL,NULL,NULL,NULL),(315,7,2,'Lake Manyara — Flamingos & Tree Lions','Drive to Lake Manyara National Park — perfect for families with shorter drives. Kids love spotting flamingos, baboons, blue monkeys, and the famous tree-climbing lions.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',6,17,NULL,NULL,NULL),(316,7,3,'Tarangire — Giants of Africa','A full day among Tarangire\'s elephant herds — the largest gatherings in East Africa. Children are amazed by the ancient baobab trees and diverse birdlife. Guided family bush walk.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',5,7,NULL,NULL,NULL),(317,7,4,'Ngorongoro Crater — Big Five Day','Descend into the Ngorongoro Crater — a natural wonder. Spot lion, elephant, buffalo, rhino and hippo. Family picnic lunch on the crater floor. Afternoon drive with junior ranger activity.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',2,16,NULL,NULL,NULL),(318,7,5,'Karatu to Arusha — Departure','Morning visit to a Maasai cultural boma — dancing, beading and storytelling with Maasai children. Drive back to Arusha for departure.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',18,NULL,NULL,NULL,NULL),(352,13,1,'Londorossi Gate to Mti Mkubwa (2,895 m)','Register at Londorossi Gate and trek through ancient forest to Big Tree Camp. The Lemosho starting point offers the most pristine wilderness approach.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(353,13,2,'Mti Mkubwa to Shira 2 Camp (3,840 m)','Long but gentle climb through heather onto the expansive Shira Plateau. Camp with sunset views of the summit.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(354,13,3,'Shira 2 to Lava Tower & Moir Hut (4,200 m)','Acclimatisation hike to Lava Tower (4,630 m). Descend to camp at Moir Hut in a remote valley on Kilimanjaro\'s northern face.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(355,13,4,'Moir Hut to Buffalo Camp (4,020 m)','Traverse the rarely-trekked northern circuit with views into Kenya and the Northern Ice Field. Few other trekkers — pure wilderness.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(356,13,5,'Buffalo Camp to Third Cave (3,870 m)','Continue the northern traverse across lava ridges. Camp at Third Cave with views of Mawenzi\'s pinnacles and the Saddle.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(357,13,6,'Third Cave to School Hut (4,750 m)','Cross the Saddle — a high-altitude desert between Mawenzi and Kibo. Arrive at School Hut for final preparations.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(358,13,7,'Summit Day — Uhuru Peak (5,895 m)','Midnight summit push via Gilman\'s Point and Stella Point to Uhuru Peak at sunrise. Descend to Millennium Camp to rest.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(359,13,8,'Millennium Camp to Mweka Camp','Descent through alpine desert and heather zones to Mweka Camp in the upper rainforest. Celebration dinner with crew.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(360,13,9,'Mweka Camp to Mweka Gate','Final trek through rainforest to Mweka Gate. Receive your summit certificate and transfer to Arusha for celebration.',NULL,'2026-04-09 18:59:24','2026-04-09 18:59:24',7,NULL,NULL,NULL,NULL),(367,3,1,'Arrival in Arusha — Welcome to Tanzania','Your Tanzanian adventure begins the moment you land at Kilimanjaro International Airport (JRO). Our professional driver-guide will be waiting at arrivals with a welcome sign, ready to transfer you to your lodge in the lush foothills of Mount Meru.\n\nSettle into your comfortable room, freshen up, and enjoy a welcome briefing over a cold drink on the terrace. Your guide will introduce the safari itinerary, share practical tips for game drives, and answer any questions. Spend the rest of the afternoon relaxing by the pool or exploring the lodge gardens with views of Mount Meru. A delicious three-course dinner rounds off your first evening in East Africa.\n\nOvernight: Arusha Coffee Lodge or similar (Bed & Breakfast)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',4,NULL,NULL,NULL,NULL),(368,3,2,'Tarangire National Park — Land of the Giants','After an early breakfast, depart Arusha and drive south-west through the Great Rift Valley escarpment to Tarangire National Park — a two-hour scenic journey through Maasai heartland dotted with traditional bomas.\n\nEnter the park and immediately be immersed in one of Tanzania\'s most underrated wildlife spectacles. Tarangire is famous for its enormous elephant herds — often 300 strong — gathering around the Tarangire River, and its ancient baobab trees that can be over 1,000 years old. During your full-day game drive, look for lions resting in the shade, leopards draped over branches, giraffes browsing the acacia woodland, and over 550 bird species including the striking yellow-collared lovebird, endemic to northern Tanzania.\n\nYour guide will position the vehicle at prime viewing spots along the river, where elephants, buffalo, and zebra come to drink in the afternoon heat. Enjoy a picnic lunch under a giant baobab before continuing your exploration. As the sun drops low, watch the savanna turn golden before heading to your lodge.\n\nOvernight: Tarangire Simba Lodge or similar (Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',5,NULL,NULL,NULL,NULL),(369,3,3,'Serengeti National Park — The Endless Plains','Rise with the sun for an early breakfast, then set off on the drive of a lifetime through the Ngorongoro Conservation Area and down into the Serengeti — Tanzania\'s most famous national park. The journey itself is extraordinary: you\'ll cross the fertile Karatu Highlands, pass Maasai villages, and stop at the Ngorongoro Crater rim viewpoint for your first breathtaking glimpse of the caldera before descending into the Serengeti ecosystem.\n\nAs you enter the Serengeti\'s Seronera Valley — the park\'s wildlife hub — the landscape opens into seemingly infinite grasslands. This central zone is renowned for year-round predator action: resident lion prides, cheetahs scanning the plains from termite mounds, and hyena clans near their dens. Your guide will read the landscape for signs of activity — circling vultures, alert Thomson\'s gazelles, and the distant dust clouds of wildebeest herds.\n\nConduct game drives en route to your camp, arriving in time for sundowners as the Serengeti sunset paints the sky in shades of amber and violet.\n\nOvernight: Serengeti Acacia Camp or similar (Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',1,NULL,NULL,NULL,NULL),(370,3,4,'Full Day in the Serengeti — Predators and Plains','Today is dedicated entirely to exploring the Serengeti — with both morning and afternoon game drives designed to maximise your wildlife encounters during the peak activity hours.\n\nDepart at dawn for a sunrise game drive when predators are most active. The early morning light is magical — watch lion prides returning from overnight hunts, spotted hyenas nursing cubs at their den, and cheetahs stretching in the first warm rays of sun. Your guide will navigate the Seronera River crossings, kopje rock formations, and open grasslands where the density of predators is among the highest in Africa.\n\nReturn to camp for a leisurely brunch, then rest during the midday heat — perhaps watching the resident vervet monkeys or the dazzling lilac-breasted rollers from your tent verandah.\n\nIn the afternoon, head out again for a second game drive focusing on different terrain — perhaps the western corridor if the migration herds are nearby, or the Moru Kopjes where ancient Maasai rock art adorns the granite boulders alongside resident leopards. Keep your camera ready for dramatic predator-prey interactions as the day cools and herd animals begin to move.\n\nOvernight: Serengeti Acacia Camp or similar (Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',1,NULL,NULL,NULL,NULL),(371,3,5,'Ngorongoro Crater — The Eighth Wonder of the World','After a final early morning game drive in the Serengeti — where every sighting feels like a gift — bid farewell to the endless plains and drive east to the Ngorongoro Conservation Area. The route climbs steadily through the Serengeti\'s acacia-studded eastern boundary and up onto the forested crater rim.\n\nCheck in at your lodge perched on the crater\'s edge, where the views are simply staggering: 600 metres below lies a 260-square-kilometre natural arena containing approximately 30,000 large mammals, including one of Africa\'s densest populations of black rhino.\n\nSpend the late afternoon soaking in the panoramic views from the rim. Watch the clouds drift across the crater floor and enjoy a spectacular sunset dinner at the lodge restaurant, where the caldera stretches below you in every shade of green and gold.\n\nOvernight: Ngorongoro Serena Safari Lodge or similar (Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',2,NULL,NULL,NULL,NULL),(372,3,6,'Ngorongoro Crater Game Drive — Departure','Rise before dawn for the experience many travellers call the highlight of their entire African safari — a half-day game drive on the Ngorongoro Crater floor. Descend the steep crater wall as morning mist lifts from the forest canopy, revealing the vast grasslands, soda lakes, and marshlands below.\n\nThe crater is home to all of the Big Five: lion, leopard, elephant, buffalo, and the critically endangered black rhinoceros. Your guide will navigate the crater\'s distinct habitats — from Lake Magadi\'s flamingo-fringed shores to the Lerai Forest where elephant bulls feed in the shade of yellow-barked acacias. Hippo pools, hyena dens, and jackal packs provide constant activity.\n\nAfter a packed picnic lunch at one of the designated picnic sites on the crater floor, ascend the rim and begin the drive back to Arusha. Your guide will stop at strategic viewpoints for final photographs. Arrive in Arusha by late afternoon for a drop-off at your hotel or Kilimanjaro International Airport, carrying memories that will last a lifetime.\n\nEnd of safari — karibu tena (welcome back anytime)!',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',2,NULL,NULL,NULL,NULL),(373,2,1,'Arrival in Arusha — VIP Welcome','Welcome to Tanzania. Upon arrival at Kilimanjaro International Airport, our VIP liaison will greet you at the aircraft door and fast-track you through immigration and customs. A luxury 4×4 transfer whisks you to your five-star lodge nestled in a coffee plantation on the slopes of Mount Meru.\n\nSettle into your elegant suite, enjoy a welcome cocktail on the terrace overlooking the manicured gardens, and join your personal safari guide for a pre-trip briefing and equipment check. If your flight arrives early, opt for a guided walk through the coffee estate or a relaxing spa treatment to shake off jet lag.\n\nA gourmet welcome dinner — featuring locally sourced Tanzanian ingredients paired with South African wines — sets the tone for the extraordinary week ahead.\n\nOvernight: Arusha Coffee Lodge or Elewana Arusha Hotel (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',4,NULL,NULL,NULL,NULL),(374,2,2,'Tarangire National Park — Elephants and Baobabs','Depart after a leisurely breakfast for the scenic two-hour drive to Tarangire National Park, passing through the Great Rift Valley with sweeping views across Maasai steppe land.\n\nTarangire is Tanzania\'s hidden gem — a park of ancient baobab trees, seasonal swamps, and the highest elephant density of any park in the country. Your luxury safari vehicle enters the park from the north, and within minutes you\'ll be surrounded by herds of elephants, their red-dust-coated silhouettes framed against towering 800-year-old baobabs.\n\nConduct a full-day game drive with a gourmet picnic lunch served at a shaded riverside spot. In the afternoon, follow the Tarangire River where elephants, buffalo, giraffes, and wildebeest congregate. Tarangire\'s birdlife is exceptional — look for the endemic ashy starling, yellow-collared lovebird, and rufous-tailed weaver.\n\nAs the sun sets, drive to your exclusive tented camp perched in the canopy of ancient trees, where a candlelit dinner awaits under the stars.\n\nOvernight: Tarangire Treetops or Chem Chem Lodge (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',5,NULL,NULL,NULL,NULL),(375,2,3,'Ngorongoro Conservation Area — Crater Rim Retreat','After a sunrise game drive in Tarangire — when the park\'s predators are most active and the light is magical — bid farewell and drive west through the charming Karatu Highlands. This fertile region, known as the breadbasket of northern Tanzania, is blanketed in coffee farms, flower plantations, and lush montane forest.\n\nContinue climbing through dense cloud forest to the rim of the Ngorongoro Crater, where you\'ll check in at one of Africa\'s most spectacular lodge locations. Your suite perches on the crater\'s edge at 2,300 metres, offering uninterrupted views across the 260-square-kilometre caldera floor.\n\nSpend the afternoon at leisure — enjoy the lodge\'s infinity pool with crater views, indulge in a hot stone spa treatment, or take a guided nature walk along the forested crater rim with a resident naturalist. In the evening, sip sundowner cocktails as the crater transforms with the setting sun, then dine in the lodge\'s panoramic restaurant.\n\nOvernight: Ngorongoro Crater Lodge or Ngorongoro Serena Lodge (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',2,NULL,NULL,NULL,NULL),(376,2,4,'Ngorongoro Crater Floor — Big Five Safari','Rise before dawn and descend 600 metres into the Ngorongoro Crater — often called the Eighth Wonder of the World. This collapsed volcanic caldera contains the highest density of wildlife in Africa, and it is one of the few places where you can realistically see all of the Big Five in a single game drive.\n\nYour luxury vehicle navigates the lush crater floor, moving between distinct habitats: open grasslands where lion prides hunt zebra and wildebeest; the shores of Lake Magadi, fringed with thousands of lesser flamingos; freshwater marshes where bull elephants and hippos wallow; and the Lerai Forest, where black rhinos browse under fever tree canopies. Your guide will take time at each sighting, positioning the vehicle for photography and explaining the remarkable ecology of this enclosed ecosystem.\n\nA gourmet picnic lunch is served at a hippo pool picnic site with views across the crater. After a full morning of exploration, ascend the rim and return to your lodge for an afternoon of relaxation, reflection, and preparation for the next chapter — the Serengeti.\n\nOvernight: Ngorongoro Crater Lodge or Ngorongoro Serena Lodge (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',2,NULL,NULL,NULL,NULL),(377,2,5,'Serengeti National Park — Into the Endless Plains','After breakfast, journey west from the Ngorongoro Highlands and descend through the dramatic Olduvai Gorge — the Cradle of Mankind, where some of humanity\'s oldest fossils were discovered. Stop at the museum for a brief orientation before continuing into the Serengeti.\n\nAs the landscape opens into the Serengeti\'s iconic golden grasslands, your guide will read the plains for wildlife activity. The central Seronera area is famous for its resident big cat populations — lion prides lounging on kopje rock formations, cheetahs scanning the horizon from termite mounds, and leopards draped over sausage tree branches.\n\nConduct game drives en route to your luxury tented camp, positioned in a private concession bordering the national park. Your camp offers the intimacy and exclusivity that distinguishes a luxury safari — just a handful of tents, each with a private deck, outdoor shower, and uninterrupted views across the Serengeti. A private chef prepares a multi-course dinner as the sounds of the bush fill the night air.\n\nOvernight: Four Seasons Safari Lodge or Singita Sabora Tented Camp (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',1,NULL,NULL,NULL,NULL),(378,2,6,'Full Day Serengeti — Dawn to Dusk Safari','Today is a full immersion in the Serengeti — widely regarded as the greatest wildlife arena on Earth. Your private guide tailors the day to your interests: big cat tracking, bird photography, migration herds, or a balanced mix of everything.\n\nDepart at first light for a dawn game drive, when the savanna comes alive. Watch lion prides returning from overnight hunts, hyena clans at their den sites, and herds of wildebeest and zebra beginning their daily grazing. The morning light — soft gold and shadow-rich — creates extraordinary photography conditions.\n\nReturn to camp for a gourmet brunch, then relax through the midday heat with a good book, a swim in the plunge pool, or an optional spa treatment. In the afternoon, venture out again for a second game drive, perhaps focusing on the Grumeti River area or the Moru Kopjes, where ancient Maasai rock paintings share the landscape with resident leopards.\n\nCap the day with a bush sundowner — champagne and canapés served at a scenic viewpoint as the Serengeti sunset blazes across the horizon.\n\nOvernight: Four Seasons Safari Lodge or Singita Sabora Tented Camp (Luxury, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',1,NULL,NULL,NULL,NULL),(379,2,7,'Charter Flight to Zanzibar — Tropical Paradise','Enjoy a final early-morning game drive in the Serengeti — each farewell drive seems to produce its own magical encounter — before transferring to the Seronera Airstrip for your charter flight to Zanzibar. Watch the Serengeti shrink beneath you as the aircraft crosses the Tanzanian landscape, trading golden savanna for the glittering Indian Ocean in under two hours.\n\nUpon landing at Zanzibar\'s Abeid Amani Karume International Airport, a private transfer whisks you to your luxury beachfront resort on the island\'s pristine east coast. Check in, settle into your ocean-view suite or private villa, and step onto powder-white sand lapped by warm turquoise water.\n\nSpend the afternoon at your own pace — snorkelling on the house reef, floating in an overwater hammock, or simply doing absolutely nothing. In the evening, dine barefoot on the beach with fresh seafood, tropical cocktails, and the sound of gentle waves.\n\nOvernight: Zuri Zanzibar or The Residence Zanzibar (Luxury Beach Resort, Full Board)',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',20,NULL,NULL,NULL,NULL),(380,2,8,'Zanzibar Exploration — Stone Town & Departure','Your final day offers a choice of experiences to close your Tanzania journey in style. Option one: sleep in, enjoy a leisurely breakfast by the ocean, and soak up the last hours of beach bliss before your afternoon transfer.\n\nOption two: join a guided morning excursion to Stone Town — Zanzibar\'s UNESCO World Heritage old quarter. Wander through narrow coral-stone alleys, visit the Sultan\'s Palace, the House of Wonders, and the historic slave market memorial. Browse the lively Darajani bazaar for spices, hand-carved Zanzibar chests, and colourful kangas. Stop at a rooftop café for spiced Zanzibari coffee and panoramic views over the harbour.\n\nAlternatively, visit a spice farm in the island\'s lush interior — touch, smell, and taste vanilla, cloves, cinnamon, cardamom, and nutmeg growing in their natural environment.\n\nAfter lunch at the resort, a private vehicle transfers you to Zanzibar airport for your onward flight. Depart with memories of roaring lions, steaming craters, elephant parades, and ocean sunsets — the very best of Tanzania.\n\nEnd of safari — asante sana na karibu tena (thank you and welcome back)!',NULL,'2026-04-09 20:10:40','2026-04-09 20:10:40',20,NULL,NULL,NULL,NULL),(442,14,1,'Full Day — Arusha National Park','Pick-up from your Arusha hotel at 7:30 AM. Drive to Arusha National Park — the hidden gem at Kilimanjaro\'s doorstep. Morning game drive through Ngurdoto Crater and Momella Lakes — spot giraffe, buffalo, flamingos and colobus monkeys. Late morning canoe safari on the Momella Lakes with hippos nearby. Picnic lunch with views of Mount Meru. Afternoon walking safari with an armed ranger. Return to Arusha by 5:30 PM.',NULL,'2026-04-10 10:27:23','2026-04-10 10:27:23',3,NULL,'media/EzdPsrJm1fiOp3GeZ0IYADq3OYo6Nh6VcHO0fnvq.png',NULL,NULL),(443,15,1,'Full Day — Tarangire National Park','Depart Arusha at 7:00 AM and drive south to Tarangire — home to the largest elephant herds in Tanzania. Morning game drive along the Tarangire River spotting elephant families, lion, leopard, python and over 500 bird species among ancient baobabs. Gourmet picnic lunch under a baobab tree. Afternoon drive into the remote southern sector for quieter wildlife sightings. Return to Arusha by 6:30 PM.',NULL,'2026-04-10 10:28:49','2026-04-10 10:28:49',5,NULL,'media/zpbtIS4neHCrzuJtYiMJm7skNnkbWozOQJvLVJ4O.jpg',NULL,NULL),(446,16,1,'Full Day — Ngorongoro Crater','Early departure from Arusha at 5:30 AM, driving through the Karatu highlands to the Ngorongoro Conservation Area. Descend 600 metres into the world\'s largest intact volcanic caldera. Game drive on the crater floor — spot the Big Five (lion, leopard, elephant, buffalo, black rhino), hippo, flamingos and jackal. Picnic lunch at a scenic lookout point. Afternoon game drive before ascending and returning to Arusha by 7:00 PM.',NULL,'2026-04-10 10:34:39','2026-04-10 10:34:39',2,NULL,'media/lLttzkO8g2HjEhbi18Vg1GsBpPglvAPlOoyQlO3T.jpg',NULL,NULL),(447,17,1,'Full Day — Materuni Village & Waterfalls','Pick-up from Arusha at 8:00 AM. Drive to the slopes of Kilimanjaro and the Chagga village of Materuni. Begin with a guided tour of a traditional coffee plantation — learn to pick, roast and brew Tanzanian coffee by hand. Continue with a scenic hike through banana plantations and lush forest to the 80-metre Materuni Waterfall — swim in the natural pool at the base. Enjoy a traditional Chagga lunch prepared by local women. Return to Arusha by 4:00 PM.',NULL,'2026-04-10 10:45:51','2026-04-10 10:45:51',22,NULL,NULL,NULL,NULL),(449,18,1,'Full Day — Lake Manyara National Park','Depart Arusha at 6:30 AM heading west along the Rift Valley escarpment. Enter Lake Manyara National Park — an emerald jewel beneath towering cliffs. Morning game drive through the groundwater forest spotting blue monkeys, elephants and the famous tree-climbing lions lounging in mahogany branches. Drive along the lakeshore for flamingo, pelican and hippo sightings. Gourmet picnic lunch with Rift Valley views. Afternoon birding drive — over 400 species recorded here. Return to Arusha by 6:00 PM.',NULL,'2026-04-10 10:50:42','2026-04-10 10:50:42',6,NULL,'media/Cut7SNutFuxMQll2QXBqIgoiNQq2HHJU6dhevJcn.jpg',NULL,NULL),(450,4,1,'Arrival in Arusha','Welcome at Kilimanjaro International Airport. Your private guide greets you and transfers you to your luxury lodge in Arusha, where you enjoy a welcome dinner and safari briefing under the African stars.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',4,21,'media/OUerMsrKMrv2SFvA0Ga24RrSyjOTtZlD2aTZFRPc.jpg',NULL,NULL),(451,4,2,'Arusha to Tarangire National Park','Drive south into the sweeping baobab-studded landscapes of Tarangire. Track elephant herds along the Tarangire River, spot tree-climbing lions and prolific birdlife. Afternoon game drive continues until sunset.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',5,7,'media/tPbNwCtQqdJP0kWm1OzJdaIjAxaeBWTSAOLIGWSl.webp',NULL,NULL),(452,4,3,'Tarangire to Central Serengeti','Early morning departure through the Great Rift Valley and Ngorongoro Highlands to reach the vast Serengeti plains. Afternoon game drive in the Seronera Valley seeking leopard, lion prides and cheetah on the open grasslands.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',1,18,'media/VyFRbvVuZN6rULbPsE6cap4n9ICM5eQi3b8vhyMc.jpg',NULL,NULL),(453,4,4,'Full Day — Serengeti Migration Zones','A full day dedicated to the Great Migration. Follow your expert guide to the current migration hot-spots — witness thousands of wildebeest and zebra on the move, river crossings, and the predators that shadow the herds. Optional sunrise hot-air balloon flight.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',1,18,'media/x3748qxPNIi3YbqZ6QFWO5CTnFMUhu0D2whFqnch.jpg',NULL,NULL),(454,4,5,'Serengeti to Ngorongoro Crater','Morning game drive en route to the Ngorongoro Conservation Area. Descend into the crater — a natural amphitheatre sheltering the densest concentration of wildlife in Africa. Spot the Big Five all in one day.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',2,16,'media/lLttzkO8g2HjEhbi18Vg1GsBpPglvAPlOoyQlO3T.jpg',NULL,NULL),(455,4,6,'Ngorongoro to Arusha — Departure','After breakfast, drive through the lush Karatu highlands back to Arusha. Enjoy a farewell lunch before your transfer to Kilimanjaro International Airport for your onward journey.',NULL,'2026-04-10 10:56:27','2026-04-10 10:56:27',4,NULL,'safaris/gallery/nz29aqUfiqfg4RcuWQ5yoMRQV7d3P3XIgbGF2y6b.jpg',NULL,NULL),(458,19,1,'Full Day — Shira Plateau Hike','Depart Arusha at 6:00 AM for the western slopes of Kilimanjaro. Drive to Londorossi Gate (2,250 m) and continue by 4x4 to the Shira Plateau trailhead (3,500 m). Hike across the ancient caldera with panoramic views of Kibo peak, the Western Breach and the Shira Cathedral. Reach the Shira Ridge viewpoint (3,800 m) for photographs. Gourmet packed lunch with a summit view. Descend and return to Arusha by 5:00 PM. A taste of Kilimanjaro without the multi-day commitment.',NULL,'2026-04-10 10:59:31','2026-04-10 10:59:31',NULL,NULL,NULL,NULL,NULL),(473,8,1,'Marangu Gate to Mandara Hut (2,720 m)','Register at Marangu Gate (1,840 m) and begin your trek through lush montane rainforest. Spot Colobus monkeys and exotic birds. Arrive at Mandara Hut — the only route with permanent sleeping huts.',NULL,'2026-04-10 11:37:32','2026-04-10 11:37:32',NULL,NULL,NULL,NULL,NULL),(474,8,2,'Mandara Hut to Horombo Hut (3,720 m)','Ascend through heather and moorland with stunning views of Mawenzi Peak. The landscape opens to alpine meadow with giant lobelias and groundsel. Arrive at Horombo for acclimatisation.',NULL,'2026-04-10 11:37:32','2026-04-10 11:37:32',NULL,NULL,NULL,NULL,NULL),(475,8,3,'Acclimatisation Day at Horombo','Critical acclimatisation day. Optional hike toward Zebra Rocks (4,000 m) for altitude training. Afternoon rest and preparation for summit night. Guides check health and monitor altitude symptoms.',NULL,'2026-04-10 11:37:32','2026-04-10 11:37:32',NULL,NULL,NULL,NULL,NULL),(476,8,4,'Horombo to Kibo Hut (4,703 m) & Summit Night','Cross the alpine desert \"Saddle\" between Mawenzi and Kibo. Arrive at Kibo Hut by afternoon. After an early dinner, begin the midnight summit push through scree and switchbacks to Uhuru Peak (5,895 m) at sunrise.',NULL,'2026-04-10 11:37:32','2026-04-10 11:37:32',NULL,NULL,NULL,NULL,NULL),(477,8,5,'Summit Descent to Marangu Gate','Descend from the summit through all climate zones back to Horombo for lunch, then continue to Marangu Gate. Receive your summit certificate and transfer back to Arusha for celebration dinner.',NULL,'2026-04-10 11:37:32','2026-04-10 11:37:32',NULL,NULL,NULL,NULL,NULL),(478,9,1,'Machame Gate to Machame Camp (3,000 m)','Begin at Machame Gate (1,800 m) and hike through pristine rainforest alive with birdsong and blue monkeys. Arrive at Machame Camp in the upper forest zone.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(479,9,2,'Machame Camp to Shira Camp (3,840 m)','Ascend through the heather zone onto the enormous Shira Plateau — one of Kilimanjaro\'s ancient calderas. Vast views of the Western Breach and the ice-capped summit.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(480,9,3,'Shira Camp to Barranco Camp (3,960 m)','Hike high toward Lava Tower (4,630 m) for acclimatisation, then descend to the spectacular Barranco Valley beneath the towering Barranco Wall. \"Walk high, sleep low\" strategy.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(481,9,4,'Barranco Wall to Karanga Camp (3,995 m)','Scale the famous Barranco Wall — a thrilling scramble with spectacular views. Continue across alpine desert to Karanga Camp, the last water collection point.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(482,9,5,'Karanga Camp to Barafu Camp (4,673 m)','Short but steep ascent to the summit base camp at Barafu. Rest and prepare for midnight summit bid. Early dinner and final gear check.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(483,9,6,'Summit Night — Uhuru Peak (5,895 m)','Midnight departure through the Arctic zone. Push through Stella Point to Uhuru Peak at sunrise. After summit photos, descend to Millennium Camp for overnight rest.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(484,9,7,'Descent to Mweka Gate','Final descent through the rainforest zone via Mweka Route. Arrive at Mweka Gate for your summit certificate and transfer to Arusha.',NULL,'2026-04-10 11:39:57','2026-04-10 11:39:57',NULL,NULL,NULL,NULL,NULL),(501,11,1,'Umbwe Gate to Umbwe Cave Camp (2,850 m)','Start at Umbwe Gate (1,600 m). Ascend steep forested ridges along a narrow trail — Kilimanjaro\'s most direct and dramatic approach.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(502,11,2,'Umbwe Cave to Barranco Camp (3,960 m)','Continue the steep climb through giant heather and moorland to reach the spectacular Barranco Valley beneath the great wall.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(503,11,3,'Barranco Wall to Karanga Camp (3,995 m)','Scale the Barranco Wall and traverse alpine desert to Karanga Camp. Acclimatisation hike in the afternoon.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(504,11,4,'Karanga to Barafu Camp (4,673 m)','Short ascent to the summit base camp. Rest and prepare for midnight summit attempt. Final gear check.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(505,11,5,'Summit Night — Uhuru Peak (5,895 m)','Midnight departure. Push through scree and switchbacks via Stella Point to the summit at sunrise. Descend to Millennium Camp.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(506,11,6,'Descent to Mweka Gate','Descend through the rainforest to Mweka Gate. Summit certificate ceremony and transfer to Arusha.',NULL,'2026-04-10 12:03:06','2026-04-10 12:03:06',NULL,NULL,NULL,NULL,NULL),(507,10,1,'Londorossi Gate to Mti Mkubwa (2,895 m)','Drive to Londorossi Gate on the western side of Kilimanjaro. Trek through pristine montane rainforest rich with blue monkeys and birdsong to the Big Tree Camp.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(508,10,2,'Mti Mkubwa to Shira 1 Camp (3,505 m)','Emerge from the forest into the heather zone. Cross streams and climb onto the vast Shira Plateau with panoramic views of Kibo peak ahead.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(509,10,3,'Shira 1 to Shira 2 Camp (3,840 m)','Traverse the Shira Plateau — one of the most scenic walks on Kilimanjaro. Giant groundsel and lobelia dot the landscape. Camp with views of the summit.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(510,10,4,'Shira 2 to Barranco Camp (3,960 m)','Acclimatisation day climbing toward Lava Tower (4,630 m), then descending to Barranco Camp in the shadow of the Great Barranco Wall.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(511,10,5,'Barranco Wall to Karanga Camp (3,995 m)','Scale the thrilling Barranco Wall with hands-on scrambling. Continue across alpine desert to Karanga Valley camp.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(512,10,6,'Karanga Camp to Barafu Camp (4,673 m)','Ascend the steep ridge to the summit base camp. Rest, hydrate, and prepare for the midnight summit push. Sunset views across the cloud sea.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(513,10,7,'Summit Night — Uhuru Peak (5,895 m)','Begin at midnight through the Arctic zone. Reach Stella Point at dawn, then push to Uhuru Peak (5,895 m). Descend to Millennium Camp.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(514,10,8,'Descent to Mweka Gate','Final descent through lush rainforest to Mweka Gate. Collect your summit certificate and celebrate with your crew before returning to Arusha.',NULL,'2026-04-10 12:04:23','2026-04-10 12:04:23',NULL,NULL,NULL,NULL,NULL),(515,12,1,'Rongai Gate to Simba Camp (2,625 m)','Drive from Arusha to the Kenyan border at Rongai Gate. Begin your trek through pine and juniper forest on Kilimanjaro\'s drier, quieter northern slopes.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(516,12,2,'Simba Camp to Second Cave (3,450 m)','Ascend through heather moorland with views stretching into Kenya. Arrive at Second Cave camp among lava formations.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(517,12,3,'Second Cave to Kikelewa Camp (3,600 m)','Traverse rocky terrain toward the Mawenzi massif. Camp at Kikelewa with dramatic views of Mawenzi\'s jagged pinnacles.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(518,12,4,'Kikelewa to Mawenzi Tarn (4,310 m)','Climb steeply to the beautiful Mawenzi Tarn — a glacial lake at the foot of Mawenzi Peak. Afternoon acclimatisation walk.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(519,12,5,'Mawenzi Tarn to School Hut (4,750 m)','Cross the lunar desert of the \"Saddle\" between Mawenzi and Kibo. Arrive at School Hut for rest before summit night.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(520,12,6,'Summit Night — Uhuru Peak (5,895 m)','Midnight start across scree to the crater rim. Reach Gilman\'s Point, then Uhuru Peak at sunrise. Descend to Horombo Hut.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL),(521,12,7,'Horombo Hut to Marangu Gate','Final descent through moorland and rainforest to Marangu Gate. Summit certificate ceremony and transfer to Arusha.',NULL,'2026-04-10 12:05:38','2026-04-10 12:05:38',NULL,NULL,NULL,NULL,NULL);
