INSERT INTO `page_sections` VALUES (13,2,'hero',0,1,'{\"slider_autoplay\":\"1\",\"slider_interval\":\"6000\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:05'),(14,2,'icon_features',2,1,'{\"heading\":{\"en\":\"Why Travel With Lomo Tanzania Safaris\",\"fr\":\"Pourquoi Voyager Avec Lomo Tanzania Safaris\",\"de\":\"Warum Mit Lomo Tanzania Safaris Reisen\",\"es\":\"Por Qu\\u00e9 Viajar Con Lomo Tanzania Safaris\"},\"subheading\":{\"en\":\"Crafting unforgettable luxury safari experiences with purpose and passion\",\"fr\":\"Cr\\u00e9er des exp\\u00e9riences de safari de luxe inoubliables avec passion et engagement\",\"de\":\"Unvergessliche Luxus-Safari-Erlebnisse mit Leidenschaft und Sinn gestalten\",\"es\":\"Creando experiencias de safari de lujo inolvidables con prop\\u00f3sito y pasi\\u00f3n\"},\"columns\":\"3\",\"bg_color\":\"#000000\",\"items\":[{\"icon\":\"heart\",\"title\":{\"en\":\"Authentic & Personalized Safaris\",\"fr\":\"Safaris Authentiques et Personnalis\\u00e9s\",\"de\":\"Authentische & Personalisierte Safaris\",\"es\":\"Safaris Aut\\u00e9nticos y Personalizados\"},\"description\":{\"en\":\"Every journey is tailor-made to match your travel style, ensuring a private and meaningful safari experience.\",\"fr\":\"Chaque voyage est con\\u00e7u sur mesure selon votre style de voyage, garantissant une exp\\u00e9rience de safari priv\\u00e9e et significative.\",\"de\":\"Jede Reise wird ma\\u00dfgeschneidert nach Ihrem Reisestil gestaltet und gew\\u00e4hrleistet ein privates und bedeutungsvolles Safari-Erlebnis.\",\"es\":\"Cada viaje est\\u00e1 hecho a medida para coincidir con su estilo de viaje, garantizando una experiencia de safari privada y significativa.\"}},{\"icon\":\"globe\",\"title\":{\"en\":\"Passion With a Purpose\",\"fr\":\"Passion Avec un But\",\"de\":\"Leidenschaft Mit Einem Zweck\",\"es\":\"Pasi\\u00f3n Con Prop\\u00f3sito\"},\"description\":{\"en\":\"Your journey supports local communities through our commitment to education, healthcare, and sustainable development.\",\"fr\":\"Votre voyage soutient les communaut\\u00e9s locales gr\\u00e2ce \\u00e0 notre engagement envers l\'\\u00e9ducation, la sant\\u00e9 et le d\\u00e9veloppement durable.\",\"de\":\"Ihre Reise unterst\\u00fctzt lokale Gemeinschaften durch unser Engagement f\\u00fcr Bildung, Gesundheitsversorgung und nachhaltige Entwicklung.\",\"es\":\"Su viaje apoya a las comunidades locales a trav\\u00e9s de nuestro compromiso con la educaci\\u00f3n, la salud y el desarrollo sostenible.\"}},{\"icon\":\"shield\",\"title\":{\"en\":\"Experienced Local Team\",\"fr\":\"\\u00c9quipe Locale Exp\\u00e9riment\\u00e9e\",\"de\":\"Erfahrenes Lokales Team\",\"es\":\"Equipo Local Experimentado\"},\"description\":{\"en\":\"With over 19 years of experience, our expert guides ensure safety, comfort, and unforgettable moments on every safari.\",\"fr\":\"Avec plus de 19 ans d\'exp\\u00e9rience, nos guides experts assurent s\\u00e9curit\\u00e9, confort et moments inoubliables \\u00e0 chaque safari.\",\"de\":\"Mit \\u00fcber 19 Jahren Erfahrung sorgen unsere erfahrenen Guides f\\u00fcr Sicherheit, Komfort und unvergessliche Momente bei jeder Safari.\",\"es\":\"Con m\\u00e1s de 19 a\\u00f1os de experiencia, nuestros gu\\u00edas expertos garantizan seguridad, comodidad y momentos inolvidables en cada safari.\"}}],\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:06'),(15,2,'safari_grid',3,1,'{\"heading\":{\"en\":\"Featured Safari Journeys\",\"fr\":\"Safaris en Vedette\",\"de\":\"Ausgew\\u00e4hlte Safari-Reisen\",\"es\":\"Safaris Destacados\"},\"subheading\":{\"en\":\"Our most sought-after luxury experiences across Tanzania\",\"fr\":\"Nos exp\\u00e9riences de luxe les plus recherch\\u00e9es en Tanzanie\",\"de\":\"Unsere gefragtesten Luxuserlebnisse in Tansania\",\"es\":\"Nuestras experiencias de lujo m\\u00e1s buscadas en Tanzania\"},\"count\":6,\"featured_only\":\"1\",\"columns\":\"3\",\"category_filter\":null,\"show_rating\":\"1\",\"slider_autoplay\":\"1\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":\"slide-up\",\"animation_speed\":\"slow\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:59:46'),(16,2,'destination_showcase',4,1,'{\"heading\":{\"en\":\"Top Safari & Adventure Destinations in Tanzania\",\"fr\":\"Meilleures Destinations Safari et Aventure en Tanzanie\",\"de\":\"Top Safari- und Abenteuer-Reiseziele in Tansania\",\"es\":\"Mejores Destinos de Safari y Aventura en Tanzania\"},\"subheading\":{\"en\":\"Explore Tanzania\'s most iconic landscapes, from wildlife-rich plains to towering mountains and breathtaking natural wonders.\",\"fr\":\"Explorez les paysages les plus embl\\u00e9matiques de la Tanzanie, des plaines riches en faune aux montagnes majestueuses et merveilles naturelles.\",\"de\":\"Entdecken Sie Tansanias ikonischste Landschaften, von wildreichen Ebenen bis zu hohen Bergen und atemberaubenden Naturwundern.\",\"es\":\"Explore los paisajes m\\u00e1s ic\\u00f3nicos de Tanzania, desde llanuras ricas en vida silvestre hasta monta\\u00f1as imponentes y maravillas naturales.\"},\"count\":6,\"featured_only\":\"1\",\"columns\":\"3\",\"category_filter\":null,\"show_rating\":\"1\",\"slider_autoplay\":\"1\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:06'),(17,2,'split_hero',1,1,'{\"heading\":{\"en\":\"Meet Lomo Tanzania Safaris\",\"fr\":\"D\\u00e9couvrez Lomo Tanzania Safaris\",\"de\":\"Lernen Sie Lomo Tanzania Safaris Kennen\",\"es\":\"Conozca Lomo Tanzania Safaris\"},\"subheading\":{\"en\":\"Less on Ourselves, More on Others\",\"fr\":\"Moins pour Nous, Plus pour les Autres\",\"de\":\"Weniger f\\u00fcr Uns, Mehr f\\u00fcr Andere\",\"es\":\"Menos para Nosotros, M\\u00e1s para los Dem\\u00e1s\"},\"body\":{\"en\":\"<p>Lomo Tanzania Safaris specializes in unforgettable journeys across Tanzania\'s Northern Safari Circuit, including Tarangire, Serengeti, Ngorongoro Crater, and Lake Manyara. Each safari is thoughtfully designed to deliver authentic wildlife encounters, cultural depth, and exceptional comfort.<\\/p><p>From your first inquiry to your final day in Tanzania, our dedicated team ensures every detail is seamless. Whether you\'re witnessing the Great Migration, exploring remote landscapes, or relaxing on the beaches of Zanzibar, every experience is crafted to be truly unforgettable.<\\/p><p>The name <strong>LOMO<\\/strong> stands for \\\"Less on Ourselves, More on Others.\\\" This principle guides our commitment to giving back through education, healthcare, and improving local living standards.<\\/p>\",\"fr\":\"<p>Lomo Tanzania Safaris se sp\\u00e9cialise dans les voyages inoubliables \\u00e0 travers le circuit safari nord de la Tanzanie, notamment le Tarangire, le Serengeti, le Crat\\u00e8re du Ngorongoro et le Lac Manyara. Chaque safari est soigneusement con\\u00e7u pour offrir des rencontres authentiques avec la faune, une profondeur culturelle et un confort exceptionnel.<\\/p><p>De votre premi\\u00e8re demande \\u00e0 votre dernier jour en Tanzanie, notre \\u00e9quipe d\\u00e9vou\\u00e9e veille \\u00e0 ce que chaque d\\u00e9tail soit parfait. Que vous assistiez \\u00e0 la Grande Migration, exploriez des paysages recul\\u00e9s ou vous d\\u00e9tendiez sur les plages de Zanzibar, chaque exp\\u00e9rience est con\\u00e7ue pour \\u00eatre v\\u00e9ritablement inoubliable.<\\/p><p>Le nom <strong>LOMO<\\/strong> signifie \\u00abLess on Ourselves, More on Others\\u00bb (Moins pour Nous, Plus pour les Autres). Ce principe guide notre engagement \\u00e0 redonner \\u00e0 travers l\'\\u00e9ducation, la sant\\u00e9 et l\'am\\u00e9lioration du niveau de vie local.<\\/p>\",\"de\":\"<p>Lomo Tanzania Safaris ist spezialisiert auf unvergessliche Reisen durch Tansanias n\\u00f6rdlichen Safari-Circuit, darunter Tarangire, Serengeti, Ngorongoro-Krater und Lake Manyara. Jede Safari ist durchdacht gestaltet, um authentische Wildtierbegegnungen, kulturelle Tiefe und au\\u00dfergew\\u00f6hnlichen Komfort zu bieten.<\\/p><p>Von Ihrer ersten Anfrage bis zu Ihrem letzten Tag in Tansania sorgt unser engagiertes Team daf\\u00fcr, dass jedes Detail nahtlos ist. Ob Sie die Gro\\u00dfe Migration erleben, abgelegene Landschaften erkunden oder an den Str\\u00e4nden von Sansibar entspannen \\u2013 jedes Erlebnis ist so gestaltet, dass es unvergesslich wird.<\\/p><p>Der Name <strong>LOMO<\\/strong> steht f\\u00fcr \\u201eLess on Ourselves, More on Others\\\". Dieses Prinzip leitet unser Engagement, durch Bildung, Gesundheitsversorgung und die Verbesserung der lokalen Lebensstandards etwas zur\\u00fcckzugeben.<\\/p>\",\"es\":\"<p>Lomo Tanzania Safaris se especializa en viajes inolvidables por el Circuito Safari del Norte de Tanzania, incluyendo Tarangire, Serengeti, Cr\\u00e1ter del Ngorongoro y Lago Manyara. Cada safari est\\u00e1 cuidadosamente dise\\u00f1ado para ofrecer encuentros aut\\u00e9nticos con la vida silvestre, profundidad cultural y un confort excepcional.<\\/p><p>Desde su primera consulta hasta su \\u00faltimo d\\u00eda en Tanzania, nuestro equipo dedicado se asegura de que cada detalle sea perfecto. Ya sea que presencie la Gran Migraci\\u00f3n, explore paisajes remotos o se relaje en las playas de Zanz\\u00edbar, cada experiencia est\\u00e1 dise\\u00f1ada para ser verdaderamente inolvidable.<\\/p><p>El nombre <strong>LOMO<\\/strong> significa \\\"Less on Ourselves, More on Others\\\" (Menos para Nosotros, M\\u00e1s para los Dem\\u00e1s). Este principio gu\\u00eda nuestro compromiso de retribuir a trav\\u00e9s de la educaci\\u00f3n, la salud y la mejora del nivel de vida local.<\\/p>\"},\"button_text\":{\"en\":\"Plan Your Safari\",\"fr\":\"Planifiez Votre Safari\",\"de\":\"Planen Sie Ihre Safari\",\"es\":\"Planifique Su Safari\"},\"button_url\":\"\\/en\\/plan-safari\",\"layout\":\"image_right\",\"image\":\"safaris\\/Sy6BdtdamfKGcVioraGTB6dbwtjfjZwRwVyYibru.png\",\"bg_color\":\"#083321\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:05'),(18,2,'testimonial_slider',6,0,'{\"heading\":{\"en\":\"What Our Guests Say\",\"fr\":\"Ce Que Disent Nos Invitu00e9s\",\"de\":\"Was Unsere Gu00e4ste Sagen\",\"es\":\"Lo Que Dicen Nuestros Huu00e9spedes\"},\"subheading\":{\"en\":\"Real stories from travelers who experienced the magic\",\"fr\":\"De vraies histoires de voyageurs qui ont vu00e9cu la magie\",\"de\":\"Echte Geschichten von Reisenden, die die Magie erlebt haben\",\"es\":\"Historias reales de viajeros que experimentaron la magia\"},\"count\":6,\"featured_only\":\"1\",\"columns\":\"3\",\"category_filter\":null,\"show_rating\":\"1\",\"slider_autoplay\":\"1\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:06'),(19,2,'image_gallery',8,1,'{\"heading\":{\"en\":\"Safari Moments\",\"fr\":\"Moments Safari\",\"de\":\"Safari-Momente\",\"es\":\"Momentos de Safari\"},\"gallery_layout\":\"grid\",\"lightbox\":\"1\",\"images\":\"itineraries\\/uk3f81rGtyx0ofjGzG0pifZg0ze5UuXNkNNt9OTQ.jpg, destinations\\/BuM271d9OojuksaVdn77Djn9f7B58dSLRDxMmUfi.jpg, destinations\\/HqMdNiFFepcNlQDKolaeVnfaIAzZbMkF1bHvBh4n.jpg, destinations\\/WN835Z2GeGeJr8burSgC4Vkk5QgGSc9DkJzzlfi0.jpg, countries\\/b3pjg3h4UktOoCh0ISZ9YcnsiEocC599rWwqrfkp.png, destinations\\/BuM271d9OojuksaVdn77Djn9f7B58dSLRDxMmUfi.jpg\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:06'),(20,2,'cta_banner',9,1,'{\"heading\":{\"en\":\"Begin Your Bespoke Safari Journey\",\"fr\":\"Commencez votre safari sur mesure\",\"de\":\"Beginnen Sie Ihre ma\\u00dfgeschneiderte Safari\",\"es\":\"Comience su safari a medida\"},\"subheading\":{\"en\":\"Entrust your dreams to our experts, who curate every detail into a journey uniquely yours. No templates\\u2014only your story, unfolding in the wild.\",\"fr\":\"Confiez vos r\\u00eaves \\u00e0 nos experts, qui fa\\u00e7onnent chaque d\\u00e9tail en un voyage qui vous est enti\\u00e8rement d\\u00e9di\\u00e9. Sans mod\\u00e8le \\u2014 seulement votre histoire, se d\\u00e9voilant au c\\u0153ur de la nature sauvage.\",\"de\":\"Vertrauen Sie Ihre Tr\\u00e4ume unseren Experten an, die jedes Detail zu einer Reise gestalten, die ganz Ihnen geh\\u00f6rt. Keine Vorlagen \\u2013 nur Ihre Geschichte, die sich in der Wildnis entfaltet.\",\"es\":\"Conf\\u00ede sus sue\\u00f1os a nuestros expertos, quienes convierten cada detalle en un viaje dise\\u00f1ado exclusivamente para usted. Sin plantillas\\u2014solo su historia, escrita en lo m\\u00e1s profundo de la naturaleza salvaje.\"},\"button_text\":{\"en\":\"Plan My Safari\",\"fr\":\"Planifier Mon Safari\",\"de\":\"Meine Safari Planen\",\"es\":\"Planificar Mi Safari\"},\"button_url\":\"\\/en\\/plan-safari\",\"bg_color\":\"#083321\",\"bg_image\":null,\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-10 12:14:38'),(21,2,'blog',10,0,'{\"heading\":{\"en\":\"Safari Insights & Stories\",\"fr\":\"Aperu00e7us & Histoires de Safari\",\"de\":\"Safari-Einblicke & Geschichten\",\"es\":\"Perspectivas e Historias de Safari\"},\"subheading\":{\"en\":\"Expert tips, travel guides, and tales from the African bush\",\"fr\":\"Conseils d\'experts, guides de voyage et ru00e9cits de la brousse africaine\",\"de\":\"Expertentipps, Reisefu00fchrer und Geschichten aus dem afrikanischen Busch\",\"es\":\"Consejos de expertos, guu00edas de viaje e historias de la sabana africana\"},\"count\":3,\"featured_only\":\"1\",\"columns\":\"3\",\"category_filter\":null,\"show_rating\":\"1\",\"slider_autoplay\":\"1\",\"design_margin_top\":null,\"design_margin_bottom\":null,\"design_padding\":null,\"design_bg_color\":\"#000000\",\"design_text_color\":\"#000000\",\"design_align\":null,\"animation_enabled\":\"1\",\"animation_type\":null,\"animation_speed\":\"medium\",\"animation_delay\":\"0\"}','2026-04-04 09:27:46','2026-04-09 13:58:06'),(22,1,'split_hero',0,1,'{\"heading\":{\"en\":\"Your Journey. Our Passion.\",\"fr\":\"Votre Voyage. Notre Passion.\",\"de\":\"Ihre Reise. Unsere Leidenschaft.\",\"es\":\"Tu Viaje. Nuestra Pasiu00f3n.\"},\"subheading\":{\"en\":\"A Safari That Changes Lives\",\"fr\":\"Un Safari Qui Change des Vies\",\"de\":\"Eine Safari, Die Leben Veru00e4ndert\",\"es\":\"Un Safari Que Cambia Vidas\"},\"body\":{\"en\":\"<p>Lomo Tanzania Safaris is a locally owned and operated safari company based in Tanzania, offering authentic and personalized safari experiences across the country\'s most iconic destinations.</p>\",\"fr\":\"<p>Lomo Tanzania Safaris est une entreprise de safari locale basu00e9e en Tanzanie, offrant des expu00e9riences de safari authentiques et personnalisu00e9es u00e0 travers les destinations les plus emblu00e9matiques du pays.</p>\",\"de\":\"<p>Lomo Tanzania Safaris ist ein lokal gefu00fchrtes Safariunternehmen mit Sitz in Tansania, das authentische und personalisierte Safarierlebnisse an den ikonischsten Reisezielen des Landes anbietet.</p>\",\"es\":\"<p>Lomo Tanzania Safaris es una empresa de safari local con sede en Tanzania, que ofrece experiencias de safari autu00e9nticas y personalizadas en los destinos mu00e1s icu00f3nicos del pau00eds.</p>\"},\"button_text\":{\"en\":\"Start Planning Your Safari\",\"fr\":\"Planifiez Votre Safari\",\"de\":\"Planen Sie Ihre Safari\",\"es\":\"Planifica Tu Safari\"},\"button_url\":\"/custom-tour\",\"layout\":\"image_right\",\"image\":\"destinations/WN835Z2GeGeJr8burSgC4Vkk5QgGSc9DkJzzlfi0.jpg\",\"bg_color\":\"#000000\"}','2026-04-04 10:25:57','2026-04-04 10:30:02'),(23,1,'image_text',1,1,'{\"heading\":{\"en\":\"Founded on Passion, Built on Experience\",\"fr\":\"Fondu00e9 sur la Passion, Construit sur l\'Expu00e9rience\",\"de\":\"Gegru00fcndet aus Leidenschaft, Aufgebaut auf Erfahrung\",\"es\":\"Fundada en la Pasiu00f3n, Construida en la Experiencia\"},\"body\":{\"en\":\"<p>Lomo Tanzania Safaris was founded by Mr. Erasto, a passionate Tanzanian wildlife guide with over 19 years of experience in the safari industry.</p><p>Born and raised in Tanzania, Erasto began his journey in 2003 at Selous Game Reserve. His deep love for wildlife led him to train at Mwewe Training College in Serengeti, where he qualified as a ranger.</p><p>Over the years, he worked with luxury camps across Serengeti, mastering the art of guiding and delivering unforgettable safari experiences.</p><p>During one safari, he met a Dutch couple who shared his vision u2014 together, they built Lomo Tanzania Safaris.</p>\",\"fr\":\"<p>Lomo Tanzania Safaris a u00e9tu00e9 fondu00e9 par M. Erasto, un guide passionnu00e9 de la faune tanzanienne avec plus de 19 ans d\'expu00e9rience dans l\'industrie du safari.</p><p>Nu00e9 et u00e9levu00e9 en Tanzanie, Erasto a commencu00e9 son parcours en 2003 u00e0 la Ru00e9serve de Selous. Son amour profond pour la faune l\'a conduit u00e0 se former au Mwewe Training College dans le Serengeti, ou00f9 il a obtenu son diplu00f4me de ranger.</p><p>Au fil des annu00e9es, il a travaillu00e9 avec des camps de luxe u00e0 travers le Serengeti, mau00eetrisant l\'art du guidage et offrant des expu00e9riences de safari inoubliables.</p><p>Lors d\'un safari, il a rencontru00e9 un couple nu00e9erlandais qui partageait sa vision u2014 ensemble, ils ont construit Lomo Tanzania Safaris.</p>\",\"de\":\"<p>Lomo Tanzania Safaris wurde von Herrn Erasto gegru00fcndet, einem leidenschaftlichen tansanischen Wildlife-Guide mit u00fcber 19 Jahren Erfahrung in der Safari-Branche.</p><p>In Tansania geboren und aufgewachsen, begann Erasto seine Reise 2003 im Selous Game Reserve. Seine tiefe Liebe zur Tierwelt fu00fchrte ihn zum Mwewe Training College im Serengeti, wo er sich als Ranger qualifizierte.</p><p>Im Laufe der Jahre arbeitete er mit Luxuscamps im Serengeti zusammen und perfektionierte die Kunst des Guidings und das Liefern unvergesslicher Safari-Erlebnisse.</p><p>Wu00e4hrend einer Safari traf er ein niederlu00e4ndisches Paar, das seine Vision teilte u2014 gemeinsam bauten sie Lomo Tanzania Safaris auf.</p>\",\"es\":\"<p>Lomo Tanzania Safaris fue fundada por el Sr. Erasto, un apasionado guu00eda de vida silvestre tanzano con mu00e1s de 19 au00f1os de experiencia en la industria del safari.</p><p>Nacido y criado en Tanzania, Erasto comenzu00f3 su viaje en 2003 en la Reserva de Selous. Su profundo amor por la vida silvestre lo llevu00f3 a formarse en el Mwewe Training College en Serengeti, donde se calificu00f3 como ranger.</p><p>A lo largo de los au00f1os, trabaju00f3 con campamentos de lujo en Serengeti, dominando el arte de guiar y ofrecer experiencias de safari inolvidables.</p><p>Durante un safari, conociu00f3 a una pareja holandesa que compartu00eda su visiu00f3n u2014 juntos, construyeron Lomo Tanzania Safaris.</p>\"},\"image\":\"countries/b3pjg3h4UktOoCh0ISZ9YcnsiEocC599rWwqrfkp.png\",\"layout\":\"image_left\"}','2026-04-04 10:25:57','2026-04-04 10:30:02'),(24,1,'highlight',2,1,'[]','2026-04-04 10:25:57','2026-04-04 10:30:02'),(25,1,'two_column_feature',3,1,'[]','2026-04-04 10:25:57','2026-04-04 10:30:02'),(26,1,'icon_features',4,1,'{\"heading\":{\"en\":\"Why Choose Us\",\"fr\":\"Pourquoi Nous Choisir\",\"de\":\"Warum Uns Wu00e4hlen\",\"es\":\"Por Quu00e9 Elegirnos\"},\"subheading\":{\"en\":\"Five reasons travelers trust Lomo Tanzania Safaris\",\"fr\":\"Cinq raisons pour lesquelles les voyageurs font confiance u00e0 Lomo Tanzania Safaris\",\"de\":\"Fu00fcnf Gru00fcnde, warum Reisende Lomo Tanzania Safaris vertrauen\",\"es\":\"Cinco razones por las que los viajeros confu00edan en Lomo Tanzania Safaris\"},\"columns\":\"3\",\"bg_color\":\"#000000\",\"items\":[{\"icon\":\"shield\",\"title\":{\"en\":\"Locally Owned Experts\",\"fr\":\"Experts Locaux\",\"de\":\"Lokale Experten\",\"es\":\"Expertos Locales\"},\"description\":{\"en\":\"Born and raised in Tanzania, our team knows every trail, every animal behavior, and every hidden gem across the country.\",\"fr\":\"Nu00e9s et u00e9levu00e9s en Tanzanie, notre u00e9quipe connau00eet chaque sentier, chaque comportement animal et chaque joyau cachu00e9 du pays.\",\"de\":\"In Tansania geboren und aufgewachsen, kennt unser Team jeden Pfad, jedes Tierverhalten und jedes versteckte Juwel des Landes.\",\"es\":\"Nacidos y criados en Tanzania, nuestro equipo conoce cada sendero, cada comportamiento animal y cada joya oculta del pau00eds.\"}},{\"icon\":\"map\",\"title\":{\"en\":\"Tailor-Made Safaris\",\"fr\":\"Safaris Sur Mesure\",\"de\":\"Mau00dfgeschneiderte Safaris\",\"es\":\"Safaris a Medida\"},\"description\":{\"en\":\"Every safari is designed around your interests, pace, and budget. No cookie-cutter itineraries u2014 only personalized experiences.\",\"fr\":\"Chaque safari est conu00e7u autour de vos intu00e9ru00eats, votre rythme et votre budget. Pas d\'itinu00e9raires standardisu00e9s u2014 uniquement des expu00e9riences personnalisu00e9es.\",\"de\":\"Jede Safari wird nach Ihren Interessen, Ihrem Tempo und Ihrem Budget gestaltet. Keine Standardreisen u2014 nur personalisierte Erlebnisse.\",\"es\":\"Cada safari estu00e1 diseu00f1ado en torno a sus intereses, ritmo y presupuesto. Sin itinerarios estu00e1ndar u2014 solo experiencias personalizadas.\"}},{\"icon\":\"heart\",\"title\":{\"en\":\"Community Impact\",\"fr\":\"Impact Communautaire\",\"de\":\"Gemeinschaftliche Wirkung\",\"es\":\"Impacto Comunitario\"},\"description\":{\"en\":\"Every booking directly supports education, healthcare, and development in local Tanzanian communities.\",\"fr\":\"Chaque ru00e9servation soutient directement l\'u00e9ducation, la santu00e9 et le du00e9veloppement des communautu00e9s locales tanzaniennes.\",\"de\":\"Jede Buchung unterstu00fctzt direkt Bildung, Gesundheitswesen und Entwicklung in lokalen tansanischen Gemeinden.\",\"es\":\"Cada reserva apoya directamente la educaciu00f3n, la salud y el desarrollo en las comunidades locales de Tanzania.\"}},{\"icon\":\"camera\",\"title\":{\"en\":\"Attention to Detail\",\"fr\":\"Attention aux Du00e9tails\",\"de\":\"Liebe zum Detail\",\"es\":\"Atenciu00f3n al Detalle\"},\"description\":{\"en\":\"From your first inquiry to your last sunset game drive, we ensure every detail is taken care of with precision and warmth.\",\"fr\":\"De votre premiu00e8re demande u00e0 votre dernier safari au coucher du soleil, nous veillons u00e0 ce que chaque du00e9tail soit pris en charge avec pru00e9cision et chaleur.\",\"de\":\"Von Ihrer ersten Anfrage bis zu Ihrer letzten Pirschfahrt bei Sonnenuntergang sorgen wir dafu00fcr, dass jedes Detail mit Pru00e4zision und Wu00e4rme erledigt wird.\",\"es\":\"Desde su primera consulta hasta su u00faltimo safari al atardecer, nos aseguramos de que cada detalle sea atendido con precisiu00f3n y calidez.\"}},{\"icon\":\"globe\",\"title\":{\"en\":\"Sustainable Tourism\",\"fr\":\"Tourisme Durable\",\"de\":\"Nachhaltiger Tourismus\",\"es\":\"Turismo Sostenible\"},\"description\":{\"en\":\"We are committed to protecting Tanzania\'s wildlife and ecosystems through responsible and sustainable travel practices.\",\"fr\":\"Nous nous engageons u00e0 protu00e9ger la faune et les u00e9cosystu00e8mes de la Tanzanie gru00e2ce u00e0 des pratiques de voyage responsables et durables.\",\"de\":\"Wir setzen uns fu00fcr den Schutz der Tierwelt und u00d6kosysteme Tansanias durch verantwortungsvolle und nachhaltige Reisepraktiken ein.\",\"es\":\"Estamos comprometidos a proteger la vida silvestre y los ecosistemas de Tanzania a travu00e9s de pru00e1cticas de viaje responsables y sostenibles.\"}}]}','2026-04-04 10:25:57','2026-04-04 10:30:02'),(27,1,'destinations',5,1,'{\"heading\":{\"en\":\"Where We Take You\",\"fr\":\"Ou00f9 Nous Vous Emmenons\",\"de\":\"Wohin Wir Sie Bringen\",\"es\":\"Adu00f3nde Te Llevamos\"},\"subheading\":{\"en\":\"Explore Tanzania\'s most iconic destinations with expert local guides\",\"fr\":\"Explorez les destinations les plus emblu00e9matiques de Tanzanie avec des guides locaux experts\",\"de\":\"Erkunden Sie Tansanias ikonischste Reiseziele mit erfahrenen lokalen Guides\",\"es\":\"Explora los destinos mu00e1s icu00f3nicos de Tanzania con guu00edas locales expertos\"},\"count\":6,\"featured_only\":\"1\",\"columns\":\"3\",\"category_filter\":null,\"show_rating\":\"1\",\"slider_autoplay\":\"1\"}','2026-04-04 10:25:57','2026-04-04 10:30:02'),(28,1,'experience_grid',6,1,'[]','2026-04-04 10:25:57','2026-04-04 10:30:02'),(29,1,'cta_banner',7,1,'{\"heading\":{\"en\":\"Join a Journey That Changes Lives\",\"fr\":\"Rejoignez un Voyage Qui Change des Vies\",\"de\":\"Werden Sie Teil einer Reise, Die Leben Veru00e4ndert\",\"es\":\"u00danete a un Viaje Que Cambia Vidas\"},\"subheading\":{\"en\":\"Every safari is more than a trip u2014 it\'s a connection, an experience, and an impact.\",\"fr\":\"Chaque safari est plus qu\'un voyage u2014 c\'est une connexion, une expu00e9rience et un impact.\",\"de\":\"Jede Safari ist mehr als eine Reise u2014 es ist eine Verbindung, ein Erlebnis und eine Wirkung.\",\"es\":\"Cada safari es mu00e1s que un viaje u2014 es una conexiu00f3n, una experiencia y un impacto.\"},\"button_text\":{\"en\":\"Start Planning\",\"fr\":\"Commencer u00e0 Planifier\",\"de\":\"Jetzt Planen\",\"es\":\"Empezar a Planificar\"},\"button_url\":\"/custom-tour\",\"bg_color\":\"#083321\",\"bg_image\":null}','2026-04-04 10:25:57','2026-04-04 10:30:02'),(30,3,'text',0,0,'{\"heading\":{\"en\":\"Safari listing intro\",\"fr\":null,\"de\":null,\"es\":null},\"body\":{\"en\":\"<p>Edit this section from the backend to control the safari listing introduction, trust signals, or planning tips shown above the grid.<\\/p>\",\"fr\":null,\"de\":null,\"es\":null}}','2026-04-05 19:13:32','2026-04-05 19:19:14'),(32,5,'text',0,0,'{\"heading\":{\"en\":\"Experiences intro\",\"fr\":null,\"de\":null,\"es\":null},\"body\":{\"en\":\"<p>Introduce your signature experiences here and keep the content fully editable from the CMS.<\\/p>\",\"fr\":null,\"de\":null,\"es\":null}}','2026-04-05 19:13:32','2026-04-06 12:08:43'),(33,6,'text',0,0,'{\"heading\":{\"en\":\"Blog intro\",\"fr\":null,\"de\":null,\"es\":null},\"body\":{\"en\":\"<p>Add editorial positioning, author notes, or featured-story copy for the blog landing page here.<\\/p>\",\"fr\":null,\"de\":null,\"es\":null}}','2026-04-05 19:13:32','2026-04-06 12:08:54'),(34,7,'text',0,0,'{\"he