DROP TABLE IF EXISTS `tripadvisor_reviews`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tripadvisor_reviews` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `tripadvisor_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reviewer_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reviewer_location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reviewer_avatar` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `title` text COLLATE utf8mb4_unicode_ci,
  `review_text` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `rating` tinyint unsigned NOT NULL,
  `review_date` date DEFAULT NULL,
  `trip_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `published` tinyint(1) NOT NULL DEFAULT '0',
  `display_order` int NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `tripadvisor_reviews_tripadvisor_id_unique` (`tripadvisor_id`),
  KEY `tripadvisor_reviews_published_index` (`published`),
  KEY `tripadvisor_reviews_display_order_index` (`display_order`)
) ENGINE=MyISAM AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

